 /**
- * Allocate an integer-cent total across positive integer weights.
- * Stub — the coding agent implements this at eval time (task 002).
+ * Splits `total` across the given positive `weights` in proportion to each
+ * weight, returning one share per weight. Throws if `weights` is empty or
+ * contains a value that is not a positive number.
  */
 export function allocateProportional(total: number, weights: number[]): number[] {
-  throw new Error(`allocateProportional not implemented (total ${total}, ${weights.length} weights)`);
+  if (weights.length === 0) {
+    throw new Error("Cannot allocate to empty weights");
+  }
+  if (weights.some(w => typeof w !== "number" || w <= 0)) {
+    throw new Error("Weights must be positive numbers");
+  }
+
+  const totalWeight = weights.reduce((sum, w) => sum + w, 0);
+
+  // Calculate the initial shares by rounding down.
+  const shares = weights.map(w => Math.floor((w / totalWeight) * total));
+
+  // Calculate the remainder due to flooring.
+  const sumOfShares = shares.reduce((sum, s) => sum + s, 0);
+  const remainder = total - sumOfShares;
+
+  // Distribute the remainder (leftover cents) to the first few shares.
+  for (let i = 0; i < remainder; i++) {
+    shares[i]++;
+  }
+
+  return shares;
 }
